from agno import Agent
import time
from typing import Dict

class TokenVault:
    def __init__(self):
        self.tokens: Dict[str, float] = {}

    def store(self, token_id: str, ttl: int = 300):
        self.tokens[token_id] = time.time() + ttl

    def get(self, token_id: str) -> bool:
        if token_id in self.tokens and time.time() < self.tokens[token_id]:
            return True
        self.tokens.pop(token_id, None)
        return False

vault = TokenVault()

def auth_guard(session):
    token_id = session.get('auth_token_id')
    if not vault.get(token_id):
        raise PermissionError('Token expired')

