from agno import Agent, Team
from enum import Enum

class AgentRole(Enum):
    OBSERVER = 'observer'
    EDITOR = 'editor'
    ADMIN = 'admin'

PERMISSIONS = {
    AgentRole.OBSERVER: ['read'],
    AgentRole.EDITOR: ['read', 'write'],
    AgentRole.ADMIN: ['read', 'write', 'delete']
}

def rbac_wrapper(role: AgentRole):
    def decorator(func):
        def wrapper(*args, **kwargs):
            action = kwargs.get('action')
            if action and action not in PERMISSIONS[role]:
                raise PermissionError(f'{role} cannot perform {action}')
            return func(*args, **kwargs)
        return wrapper
    return decorator

@rbac_wrapper(AgentRole.EDITOR)
def team_write_action(data):
    return {'status': 'written'}

team = Team(agents=[Agent(tools=[team_write_action])])
